item.aggregated_output:
:root {
  color-scheme: light;
  --bg: #f3efe4;
  --panel: rgba(255, 251, 242, 0.88);
  --panel-strong: #fffaf0;
  --ink: #1d2a22;
  --muted: #526257;
  --line: rgba(29, 42, 34, 0.12);
  --accent: #1d6b52;
  --accent-2: #d57a3d;
  --shadow: 0 22px 60px rgba(39, 42, 24, 0.12);
}

* {
  box-sizing: border-box;
}

html {
  font-size: 16px;
}

body {
  margin: 0;
  color: var(--ink);
  font-family: Georgia, "Times New Roman", serif;
  background:
    radial-gradient(circle at top left, rgba(213, 122, 61, 0.22), transparent 32%),
    radial-gradient(circle at top right, rgba(29, 107, 82, 0.18), transparent 28%),
    linear-gradient(180deg, #f7f3e9 0%, var(--bg) 100%);
}

body::before {
  position: fixed;
  inset: 0;
  pointer-events: none;
  content: "";
  background-image:
    linear-gradient(rgba(29, 42, 34, 0.04) 1px, transparent 1px),
    linear-gradient(90deg, rgba(29, 42, 34, 0.04) 1px, transparent 1px);
  background-size: 28px 28px;
  mask-image: linear-gradient(180deg, rgba(0, 0, 0, 0.5), transparent 85%);
}

.page {
  width: min(1100px, calc(100% - 2rem));
  margin: 0 auto;
  padding: 2rem 0 4rem;
}

.hero,
.panel {
  border: 1px solid var(--line);
  border-radius: 24px;
  background: var(--panel);
  box-shadow: var(--shadow);
  backdrop-filter: blur(6px);
}

.hero {
  position: relative;
  overflow: hidden;
  margin-bottom: 1.5rem;
  padding: 3rem;
}

.hero::after {
  position: absolute;
  right: -5rem;
  bottom: -5rem;
  width: 16rem;
  height: 16rem;
  border-radius: 50%;
  content: "";
  background: radial-gradient(circle, rgba(213, 122, 61, 0.38), transparent 68%);
}

.eyebrow {
  margin: 0 0 0.75rem;
  color: var(--accent);
  font-size: 0.8rem;
  font-weight: 700;
  letter-spacing: 0.2em;
  text-transform: uppercase;
}

h1,
h2 {
  margin: 0 0 0.8rem;
  line-height: 1.05;
  font-weight: 700;
}

h1 {
  max-width: 14ch;
  font-size: clamp(2.4rem, 5vw, 4.8rem);
}

h2 {
  font-size: clamp(1.5rem, 3vw, 2.2rem);
}

p,
li,
td,
th,
code {
  line-height: 1.6;
}

.lead {
  max-width: 58ch;
  margin: 0 0 1.5rem;
  color: var(--muted);
  font-size: 1.08rem;
}

.hero-actions {
  display: flex;
  gap: 0.8rem;
  flex-wrap: wrap;
}

a {
  color: inherit;
}

.hero-actions a {
  display: inline-block;
  padding: 0.8rem 1.2rem;
  border: 1px solid transparent;
  border-radius: 999px;
  background: var(--accent);
  color: #f8f5ef;
  text-decoration: none;
  transition: transform 160ms ease, background 160ms ease;
}

.hero-actions a:hover,
.hero-actions a:focus-visible {
  transform: translateY(-1px);
  background: #155640;
}

.hero-actions .secondary {
  border-color: var(--line);
  background: transparent;
  color: var(--ink);
}

.grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 1.5rem;
  margin-bottom: 1.5rem;
}

.panel {
  margin-bottom: 1.5rem;
  padding: 1.6rem 1.7rem;
}

ul {
  padding-left: 1.2rem;
}

pre {
  overflow-x: auto;
  margin: 1rem 0 0;
  padding: 1rem 1.1rem;
  border: 1px solid rgba(29, 42, 34, 0.08);
  border-radius: 18px;
  background: var(--panel-strong);
}

code,
pre {
  font-family: "Consolas", "Courier New", monospace;
  font-size: 0.96rem;
}

.table-wrap {
  overflow-x: auto;
}

table {
  width: 100%;
  border-collapse: collapse;
}

th,
td {
  padding: 0.8rem 0.6rem;
  border-bottom: 1px solid var(--line);
  text-align: left;
  vertical-align: top;
}

th {
  font-size: 0.8rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--muted);
}

@media (max-width: 780px) {
  .page {
    width: min(100% - 1rem, 100%);
    padding-top: 0.75rem;
  }

  .hero,
  .panel {
    border-radius: 20px;
  }

  .hero {
    padding: 1.5rem;
  }

  .grid {
    grid-template-columns: 1fr;
    gap: 0;
  }

  .panel {
    padding: 1.25rem;
  }
}
